import { prisma } from '@/lib/prisma'
import Link from 'next/link'
import { Clock, ShieldCheck, ChevronRight } from 'lucide-react'
import Countdown from '@/components/countdown/Countdown'
import EventTimeDisplay from '@/components/EventTimeDisplay'

// Force Next.js to always render fresh data from the DB for the homepage
export const dynamic = 'force-dynamic'

export default async function HomePage() {
  const now = new Date()

  // 1. Fetch the 4 most urgent EXACT upcoming events
  const futureEvents = await prisma.event.findMany({
    where: { 
      dueAt: { gt: now },
      dateStatus: 'EXACT' 
    },
    orderBy: { dueAt: 'asc' },
    take: 4
  })

  const primaryEvent = futureEvents[0]
  const upNextEvents = futureEvents.slice(1, 4)

  // 2. Fetch the Trending events
  const trendingEvents = await prisma.event.findMany({
    where: { trending: true },
    orderBy: { dueAt: 'asc' },
    take: 8
  })

  // 3. Calculate "Last Updated" for the Trust Strip
  let updatedString = 'Just now'
  if (primaryEvent) {
    const diffMins = Math.floor((now.getTime() - primaryEvent.updatedAt.getTime()) / 60000)
    updatedString = diffMins < 60 ? `${diffMins}m ago` : `${Math.floor(diffMins / 60)}h ago`
  }

  return (
    <main className="min-h-screen bg-black text-white selection:bg-emerald-500/30 pb-20">
      <div className="max-w-6xl mx-auto px-5 py-12 md:py-20">
        
        {/* ============================================== */}
        {/* HERO: NEXT-DUE TERMINAL WITH PROOF RAIL        */}
        {/* ============================================== */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-20">
          
          {/* LEFT: PRIMARY TERMINAL MODULE (Spans 2 columns) */}
          <div className="lg:col-span-2 rounded-3xl border border-zinc-800 bg-zinc-950 p-6 md:p-10 shadow-2xl relative overflow-hidden flex flex-col justify-between group">
            
            {/* Subtle Aliveness Glow */}
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[100%] h-32 bg-emerald-500/10 blur-[80px] pointer-events-none transition-opacity group-hover:opacity-100 opacity-70" />
            
            {primaryEvent ? (
              <>
                <div>
                  {/* TRUST STRIP */}
                  <div className="flex flex-wrap items-center gap-3 mb-6 relative z-10">
                    <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest text-emerald-400 bg-emerald-400/10 px-2.5 py-1 rounded-md border border-emerald-400/20">
                      <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                      Live Sync
                    </div>
                    <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest text-zinc-400">
                      <Clock className="w-3 h-3" />
                      Updated {updatedString}
                    </div>
                    <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest text-zinc-400">
                      <ShieldCheck className="w-3 h-3" />
                      Verified
                    </div>
                  </div>

                  <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-zinc-500 mb-2 relative z-10">
                    Next Critical Event • {primaryEvent.category}
                  </h2>
                  <Link href={`/${primaryEvent.category.toLowerCase()}/${primaryEvent.slug}`} className="block relative z-10 group-hover:text-emerald-300 transition-colors">
                    <h1 className="text-4xl md:text-5xl lg:text-6xl font-black tracking-tight mb-8">
                      {primaryEvent.title}
                    </h1>
                  </Link>
                </div>

                <div className="relative z-10">
                  <div className="bg-black/60 border border-zinc-800 p-5 rounded-2xl mb-6 backdrop-blur-md">
                    <Countdown targetIso={primaryEvent.dueAt!.toISOString()} />
                  </div>
                  
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <EventTimeDisplay dueAt={primaryEvent.dueAt!} officialZone={primaryEvent.timeZone || 'UTC'} />
                    <Link href={`/${primaryEvent.category.toLowerCase()}/${primaryEvent.slug}`} className="flex items-center justify-center gap-2 bg-white text-black px-6 py-4 rounded-xl font-bold text-sm hover:scale-105 transition-transform shrink-0">
                      Full Event Intel <ChevronRight className="w-4 h-4" />
                    </Link>
                  </div>
                </div>
              </>
            ) : (
              <div className="flex items-center justify-center h-full text-zinc-500">No upcoming events found. Add some in the Admin Control Room.</div>
            )}
          </div>

          {/* RIGHT: UP NEXT / PROOF RAIL */}
          <div className="flex flex-col gap-4">
            <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-zinc-500 px-2">Up Next By Category</h3>
            {upNextEvents.map((evt) => (
              <Link href={`/${evt.category.toLowerCase()}/${evt.slug}`} key={evt.id} className="block group h-full">
                <div className="rounded-2xl border border-zinc-800 bg-zinc-900/40 p-5 hover:bg-zinc-800/80 transition-all hover:border-zinc-700 h-full flex flex-col justify-between relative overflow-hidden">
                  {/* Accent Line */}
                  <div className="absolute top-0 left-0 w-1 h-full bg-zinc-800 group-hover:bg-emerald-500 transition-colors" />
                  
                  <div>
                    <div className="flex items-center justify-between mb-3">
                      <span className="text-[9px] font-bold uppercase tracking-widest text-emerald-400 bg-emerald-400/10 px-2 py-0.5 rounded border border-emerald-400/20">
                        {evt.category}
                      </span>
                    </div>
                    <h4 className="text-base font-bold text-white group-hover:text-emerald-300 transition-colors line-clamp-2 mb-4">
                      {evt.title}
                    </h4>
                  </div>
                  
                  <div>
                    <p className="text-xl font-black tabular-nums text-white">
                      {new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric' }).format(evt.dueAt!)}
                    </p>
                    <p className="text-[10px] text-zinc-500 font-medium uppercase tracking-widest mt-1">
                      {new Intl.DateTimeFormat('en-US', { weekday: 'long', timeZone: 'UTC' }).format(evt.dueAt!)}
                    </p>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>

        {/* ============================================== */}
        {/* TRENDING GRID                                  */}
        {/* ============================================== */}
        <div className="mb-8 flex items-center justify-between">
          <h2 className="text-lg font-bold text-white flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.8)]" />
            Trending Countdowns
          </h2>
        </div>
        
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {trendingEvents.map((evt) => (
             <Link href={`/${evt.category.toLowerCase()}/${evt.slug}`} key={evt.id} className="block group">
               <div className="rounded-2xl border border-zinc-800 bg-zinc-950 p-5 hover:border-zinc-600 transition-colors relative h-full flex flex-col justify-between">
                 
                 {/* Urgent Imminent Badge */}
                 {evt.dateStatus === 'EXACT' && evt.dueAt && evt.dueAt.getTime() < now.getTime() + 86400000 && evt.dueAt.getTime() > now.getTime() && (
                   <div className="absolute -top-3 -right-2 bg-emerald-500 text-black text-[9px] font-bold uppercase tracking-widest px-2 py-1 rounded-md shadow-[0_0_15px_rgba(16,185,129,0.5)] z-10">
                     Imminent
                   </div>
                 )}

                 <div>
                  <p className="text-[10px] font-bold uppercase tracking-widest text-zinc-500 mb-2">{evt.category}</p>
                  <h3 className="text-sm font-bold text-white mb-6 line-clamp-2 group-hover:text-emerald-300 transition-colors">{evt.title}</h3>
                 </div>
                 
                 {evt.dateStatus === 'EXACT' && evt.dueAt ? (
                   <p className="text-lg font-black text-white tabular-nums">
                     {new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC' }).format(evt.dueAt)}
                   </p>
                 ) : (
                   <p className="text-sm font-bold text-amber-400 uppercase tracking-widest">
                     {evt.dateLabel || 'TBA'}
                   </p>
                 )}
               </div>
             </Link>
          ))}
        </div>

      </div>
    </main>
  )
}